import { useContext, useEffect } from "react";
import { Table, Container, Card } from "react-bootstrap";
import UserContext from "./context";
import axios from "axios";

export default function TransactionHistory() {
    const { user, setUser } = useContext(UserContext);

    useEffect(() => {
        const fetchLatestData = async () => {
            try {
                const res = await axios.get('http://localhost:8080/api/users/profile');
                setUser(res.data);
            } catch (err) {
                console.error("Error fetching latest transactions:", err);
            }
        };
        if (user) fetchLatestData();
    }, []);

    if (!user) return <Container className="mt-5"><h3>Please login to view your transaction history.</h3></Container>;

    return (
        <Container className="mt-5">
            <Card className="shadow border-0">
                <Card.Header className="bg-dark text-white text-center py-3">
                    <h2 className="mb-0">Money Tracking</h2>
                </Card.Header>
                <Card.Body className="p-4">
                    <div className="d-flex justify-content-between align-items-center mb-4">
                        <h5 className="text-secondary mb-0">User: {user.name}</h5>
                        <h4 className="text-primary fw-bold mb-0">Balance: ₹{user.amount}</h4>
                    </div>
                    <Table striped bordered hover responsive className="text-center">
                        <thead className="table-dark">
                            <tr>
                                <th>TYPE</th>
                                <th>AMOUNT</th>
                                <th>DATE & TIME</th>
                            </tr>
                        </thead>
                        <tbody>
                            {user.transactions && user.transactions.length > 0 ? (
                                user.transactions.slice().reverse().map((tx, index) => (
                                    <tr key={index}>
                                        <td className={tx.type === 'deposit' ? 'text-success fw-bold' : 'text-danger fw-bold'}>
                                            {tx.type.toUpperCase()}
                                        </td>
                                        <td className="fw-bold">₹{tx.amount}</td>
                                        <td className="text-muted">{new Date(tx.date).toLocaleString()}</td>
                                    </tr>
                                ))
                            ) : (
                                <tr>
                                    <td colSpan="3" className="py-4 text-center text-muted">No transactions found.</td>
                                </tr>
                            )}
                        </tbody>
                    </Table>
                </Card.Body>
            </Card>
        </Container>
    );
}
